UPDATE google_calendar_oauth_attempts SET status='cancelled', error_code='authorization_superseded', updated_at=now() WHERE user_id='b664fc22-69d3-40f1-8370-16b8a07ec402' AND status IN ('starting','waiting_authorization','completing'); UPDATE google_calendar_connections SET status='disconnected', active_oauth_attempt_id=NULL, updated_at=now() WHERE user_id='b664fc22-69d3-40f1-8370-16b8a07ec402' AND status IN ('starting','waiting_authorization','completing','preparing_calendar');